{% from 'templates/print_formats/standard_macros.html' import add_header %}
{% set print_settings = frappe.get_doc('Print Settings') %}
<!DOCTYPE html>
<html>
<head>
  <title>{{ doc.project_title }}</title>
  <style>
    body { font-family: Arial, sans-serif; font-size: 12px; }
    .header { background: #003366; color: white; padding: 16px; text-align: center; }
    .section-title { background: #e8f0fe; padding: 6px 12px; font-weight: bold; margin: 12px 0 6px; }
    table { width: 100%; border-collapse: collapse; }
    td, th { border: 1px solid #ccc; padding: 6px 10px; }
    th { background: #f5f5f5; }
    .badge { display: inline-block; padding: 2px 10px; border-radius: 12px; color: white; }
    .badge-active { background: #28a745; }
    .badge-draft  { background: #6c757d; }
  </style>
</head>
<body>
  <div class='header'>
    <h2>Research Project</h2>
    <h3>{{ doc.project_title }}</h3>
    <p>{{ doc.project_code }} | {{ doc.therapeutic_area }}</p>
  </div>
  <br/>
  <div class='section-title'>Project Details</div>
  <table>
    <tr><th>Principal Investigator</th><td>{{ doc.principal_investigator }}</td><th>Phase</th><td>{{ doc.research_phase }}</td></tr>
    <tr><th>Status</th><td>{{ doc.status }}</td><th>Priority</th><td>{{ doc.priority }}</td></tr>
    <tr><th>Start Date</th><td>{{ doc.start_date }}</td><th>End Date</th><td>{{ doc.end_date }}</td></tr>
    <tr><th>Budget</th><td>{{ frappe.format(doc.budget, 'Currency') }}</td><th>Drug Modality</th><td>{{ doc.drug_modality }}</td></tr>
  </table>
  {% if doc.objectives %}
  <div class='section-title'>Objectives</div>
  <p>{{ doc.objectives }}</p>
  {% endif %}
  {% if doc.milestones %}
  <div class='section-title'>Milestones</div>
  <table>
    <tr><th>Milestone</th><th>Due Date</th><th>Status</th></tr>
    {% for m in doc.milestones %}
    <tr><td>{{ m.milestone_name }}</td><td>{{ m.due_date }}</td><td>{{ m.status }}</td></tr>
    {% endfor %}
  </table>
  {% endif %}
</body>
</html>
